solution.text:
\textbf{Step 1: Solve the general case.}
Let $A\sim\text{Unif}\{1,\dots,m\}$ and $B\sim\text{Unif}\{1,\dots,n\}$, independent.
Then
\[
\mathbb{P}(A < B)
=\sum_{a=1}^m \mathbb{P}(A = a)\,\mathbb{P}(B > a)
=\frac{1}{m}\sum_{a=1}^m \frac{n-a}{n}\;\mathbf{1}\{a\le n\}.
\]
If $m\le n$ (true in both games), then $\mathbf{1}\{a\le n\}=1$ for all $a\le m$, so
\[
\mathbb{P}(A < B)
=\frac{1}{mn}\sum_{a=1}^m (n-a)
=\frac{1}{mn}\left(mn-\sum_{a=1}^m a\right).
\]
Using $\sum_{a=1}^m a=\frac{m(m+1)}{2}$,
\[
\boxed{
\mathbb{P}(A < B)=1-\frac{m+1}{2n}
\qquad (m\le n).
}
\]

\par\textbf{Step 2: Apply to Game 1 ($m=5$, $n=10$).}
\[
\mathbb{P}_1(A < B)=1-\frac{5+1}{2\cdot 10}
=1-\frac{6}{20}
=1-\frac{3}{10}
=\frac{7}{10}.
\]

\par\textbf{Step 3: Apply to Game 2 ($m=50$, $n=100$).}
\[
\mathbb{P}_2(A < B)=1-\frac{50+1}{2\cdot 100}
=1-\frac{51}{200}
=\frac{149}{200}.
\]

\par\textbf{Step 4: Compare the two probabilities.}
\[
\frac{7}{10}=\frac{140}{200},
\qquad
\frac{149}{200}>\frac{140}{200}.
\]
So Game 2 gives a higher chance to win.

\par\textbf{Conclusion.}
\[
\boxed{
\text{Alice should choose Game 2, since }\mathbb{P}_2(A < B)=\frac{149}{200}=0.745
\text{ exceeds }\mathbb{P}_1(A < B)=\frac{7}{10}=0.70.
}
\]

